#!/usr/bin/env node
import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const gnosisMathRoot = path.join(process.cwd(), 'open-source/gnosis-math/Gnosis');
const auditPath = path.join(
  process.cwd(),
  'apps/mcp-superserver/src/ledger-tool-audit.generated.json'
);
const ledgerPath = path.join(process.cwd(), 'open-source/gnosis/THEOREM_LEDGER.md');
const ownershipPath = path.join(
  process.cwd(),
  'open-source/gnosis/scripts/ledger-mcp-ownership.ts'
);

const ledgerStart = '<!-- gnosis-math-mcp-placement:start -->';
const ledgerEnd = '<!-- gnosis-math-mcp-placement:end -->';
const ownershipStart = '  // gnosis-math-mcp-placement:start';
const ownershipEnd = '  // gnosis-math-mcp-placement:end';

const serverRules = [
  [/amplituhedron|quantum|qkv|attention|wave|spectral|physics|particle|boson|fermion|vacuum|blackhole|black_hole/iu, 'quantum-mcp'],
  [/relativ|lorentz|gravity|gravit|cosmic|cosmolog|spacetime|hawking/iu, 'relativity-mcp'],
  [/thermo|heat|entropy|metabolism|temperature|landauer/iu, 'thermodynamics-mcp'],
  [/queue|ergodic|markov|harris|recurrence|stability|stationary/iu, 'ergodicity-mcp'],
  [/buley|buleyean|godformula|god_formula|kernel|sliver|clinamen|gnostic|void/iu, 'god-formula-mcp'],
  [/mesh|topolog|braid|knot|homology|betti|manifold|cobordism|fano|octonion|catmap|arnold|mckay|ade|langlands/iu, 'topology-mcp'],
  [/govern|constitution|law|justice|liability|compliance|torah|jubilee|rights/iu, 'governance-mcp'],
  [/market|hft|trading|finance|vwap|orderbook|netflix|economics|auction|tariff/iu, 'economics-mcp'],
  [/genom|dna|cancer|bio|immune|autoimmunity|cell|protein/iu, 'genomics-mcp'],
  [/sleep|dream/iu, 'sleep-mcp'],
  [/emotion|affect|anxiety|grief|forgive|recovery|therapy|mindful|psyche|conscious/iu, 'emotion-mcp'],
  [/language|linguistic|grammar|chomsky|poe|borges|leibniz|laplace|plato|aristotle|zeno|cicero|parable|witness/iu, 'philosophy-mcp'],
  [/security|adversarial|attack|deception|fraud|byzantine/iu, 'cybersecurity-mcp'],
  [/protocol|server|runtime|compiler|scheduler|forkracefold|fork_race_fold/iu, 'verification-mcp'],
];

function walkLeanFiles(directory, files = []) {
  for (const entry of readdirSync(directory, { withFileTypes: true })) {
    const fullPath = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      walkLeanFiles(fullPath, files);
    } else if (entry.isFile() && entry.name.endsWith('.lean')) {
      files.push(fullPath);
    }
  }
  return files;
}

function moduleNameFromPath(filePath) {
  return path
    .relative(gnosisMathRoot, filePath)
    .replace(/\.lean$/u, '')
    .split(path.sep)
    .join('/');
}

function likelyServerForModule(moduleName) {
  for (const [pattern, server] of serverRules) {
    if (pattern.test(moduleName)) return server;
  }
  return 'verification-mcp';
}

function countPattern(source, pattern) {
  return [...source.matchAll(pattern)].length;
}

function stripLeanComments(source) {
  let output = '';
  for (let index = 0; index < source.length; ) {
    if (source.startsWith('/-', index)) {
      let depth = 1;
      index += 2;
      while (index < source.length && depth > 0) {
        if (source.startsWith('/-', index)) {
          depth += 1;
          index += 2;
        } else if (source.startsWith('-/', index)) {
          depth -= 1;
          index += 2;
        } else {
          index += 1;
        }
      }
    } else if (source.startsWith('--', index)) {
      while (index < source.length && source[index] !== '\n') index += 1;
    } else if (source[index] === '"') {
      output += ' ';
      index += 1;
      while (index < source.length) {
        if (source[index] === '\\') {
          output += '  ';
          index += 2;
        } else if (source[index] === '"') {
          output += ' ';
          index += 1;
          break;
        } else {
          output += source[index] === '\n' ? '\n' : ' ';
          index += 1;
        }
      }
    } else {
      output += source[index];
      index += 1;
    }
  }
  return output;
}

function firstDeclaration(source) {
  const match = source.match(
    /^\s*(theorem|lemma|def|structure|inductive)\s+([A-Za-z0-9_'.]+)/mu
  );
  return match ? `${match[1]} ${match[2]}` : 'module import surface';
}

function referencedGnosisMathModules() {
  const audit = JSON.parse(readFileSync(auditPath, 'utf8'));
  const modules = new Set();
  for (const entry of audit.entries) {
    const prefix = 'open-source/gnosis-math/Gnosis/';
    if (
      entry.proofArtifactPath.startsWith(prefix) &&
      entry.proofArtifactPath.endsWith('.lean')
    ) {
      modules.add(entry.proofArtifactPath.slice(prefix.length, -'.lean'.length));
    }
  }
  return modules;
}

function existingPlacementModules(ledger) {
  const start = ledger.indexOf(ledgerStart);
  const end = ledger.indexOf(ledgerEnd);
  if (start === -1 || end === -1 || end < start) return new Set();
  const block = ledger.slice(start, end);
  const modules = new Set();
  const modulePattern = /Lean module `([^`]+)` in `Gnosis\/[^`]+\.lean`/gu;
  for (const match of block.matchAll(modulePattern)) {
    modules.add(match[1]);
  }
  return modules;
}

function sanitizeId(moduleName) {
  return moduleName
    .replace(/([a-z0-9])([A-Z])/gu, '$1-$2')
    .replace(/[^A-Za-z0-9]+/gu, '-')
    .replace(/^-|-$/gu, '')
    .toUpperCase();
}

function auditModule(filePath) {
  const source = readFileSync(filePath, 'utf8');
  const code = stripLeanComments(source);
  const moduleName = moduleNameFromPath(filePath);
  return {
    moduleName,
    path: `open-source/gnosis-math/Gnosis/${moduleName}.lean`,
    server: likelyServerForModule(moduleName),
    theoremCount: countPattern(code, /^\s*theorem\s+/gmu),
    lemmaCount: countPattern(code, /^\s*lemma\s+/gmu),
    defCount: countPattern(code, /^\s*def\s+/gmu),
    typeCount:
      countPattern(code, /^\s*structure\s+/gmu) +
      countPattern(code, /^\s*inductive\s+/gmu),
    hasSorry: /\bsorry\b/u.test(code),
    hasAdmit: /\badmit\b/u.test(code),
    hasAxiom: /^\s*axiom\s+/mu.test(code),
    firstDeclaration: firstDeclaration(code),
  };
}

function replaceMarkedBlock(source, start, end, replacement) {
  const pattern = new RegExp(
    `${escapeRegExp(start)}[\\s\\S]*?${escapeRegExp(end)}\\n?`,
    'u'
  );
  if (pattern.test(source)) {
    return source.replace(pattern, `${replacement}\n`);
  }
  return `${source.trimEnd()}\n\n${replacement}\n`;
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/gu, '\\$&');
}

function sectionForServer(server) {
  return `Gnosis Math Placement -- ${server} (2026-05-11)`;
}

function obligationLabel(moduleAudit) {
  const flags = [
    moduleAudit.hasSorry ? 'sorry' : '',
    moduleAudit.hasAdmit ? 'admit' : '',
    moduleAudit.hasAxiom ? 'axiom' : '',
  ].filter(Boolean);
  return flags.length > 0 ? `open obligations: ${flags.join(', ')}` : 'clean scan';
}

function renderLedgerBlock(moduleAudits) {
  const byServer = new Map();
  for (const moduleAudit of moduleAudits) {
    const bucket = byServer.get(moduleAudit.server) ?? [];
    bucket.push(moduleAudit);
    byServer.set(moduleAudit.server, bucket);
  }

  const lines = [
    ledgerStart,
    '',
    '## Gnosis Math MCP Placement Anchors (2026-05-11)',
    '',
    'Generated by `node open-source/gnosis/scripts/place-gnosis-math-mcp-gaps.mjs`.',
    'These rows provide one MCP-owned anchor per previously unreferenced `open-source/gnosis-math/Gnosis/**/*.lean` module. Rows marked with open obligations link the file without claiming a closed proof surface.',
  ];

  for (const [server, modules] of [...byServer.entries()].sort(([a], [b]) =>
    a.localeCompare(b)
  )) {
    lines.push(
      '',
      `### ${sectionForServer(server)}`,
      '',
      '| ID | Claim (paper-level) | Explicit assumptions | Mechanization | Status |',
      '|---|---|---|---|---|'
    );
    for (const moduleAudit of modules.sort((left, right) =>
      left.moduleName.localeCompare(right.moduleName)
    )) {
      const id = `THM-GNOSIS-MATH-PLACEMENT-${sanitizeId(moduleAudit.moduleName)}`;
      const status =
        moduleAudit.hasSorry || moduleAudit.hasAdmit || moduleAudit.hasAxiom
          ? '`linked-open-obligations`'
          : '`mechanized`';
      lines.push(
        `| \`${id}\` | MCP placement anchor for Gnosis Math module \`${moduleAudit.moduleName}\`. | ${obligationLabel(moduleAudit)}; declarations: ${moduleAudit.theoremCount} theorems, ${moduleAudit.lemmaCount} lemmas, ${moduleAudit.defCount} defs, ${moduleAudit.typeCount} types; first declaration \`${moduleAudit.firstDeclaration}\` | Lean module \`${moduleAudit.moduleName}\` in \`Gnosis/${moduleAudit.moduleName}.lean\` | ${status} |`
      );
    }
  }

  lines.push('', ledgerEnd);
  return lines.join('\n');
}

function renderOwnershipBlock(moduleAudits) {
  const servers = [...new Set(moduleAudits.map((moduleAudit) => moduleAudit.server))].sort();
  const lines = [ownershipStart];
  for (const server of servers) {
    lines.push(`  { section: '${sectionForServer(server)}', server: '${server}' },`);
  }
  lines.push(ownershipEnd);
  return lines.join('\n');
}

function insertOwnershipBlock(source, block) {
  if (source.includes(ownershipStart)) {
    return replaceMarkedBlock(source, ownershipStart, ownershipEnd, block);
  }
  const anchor =
    "  { section: 'TopologicalMetabolism Promotion (2026-05-11)', server: 'thermodynamics-mcp' },";
  if (!source.includes(anchor)) {
    throw new Error(`Could not find ownership insertion anchor: ${anchor}`);
  }
  return source.replace(anchor, `${anchor}\n${block}`);
}

function main() {
  const ledger = readFileSync(ledgerPath, 'utf8');
  const referenced = referencedGnosisMathModules();
  const existingPlacements = existingPlacementModules(ledger);
  const moduleAudits = walkLeanFiles(gnosisMathRoot)
    .map(auditModule)
    .filter(
      (moduleAudit) =>
        existingPlacements.has(moduleAudit.moduleName) ||
        !referenced.has(moduleAudit.moduleName)
    )
    .sort((left, right) => left.moduleName.localeCompare(right.moduleName));

  if (moduleAudits.length === 0) {
    console.log('No unreferenced gnosis-math modules remain.');
    return;
  }

  writeFileSync(
    ledgerPath,
    replaceMarkedBlock(ledger, ledgerStart, ledgerEnd, renderLedgerBlock(moduleAudits)),
    'utf8'
  );

  const ownership = readFileSync(ownershipPath, 'utf8');
  writeFileSync(
    ownershipPath,
    insertOwnershipBlock(ownership, renderOwnershipBlock(moduleAudits)),
    'utf8'
  );

  console.log(`Placed ${moduleAudits.length} gnosis-math modules across MCP ledgers.`);
}

main();
